import AVFoundation
import Speech

class VoiceRecorder: NSObject, ObservableObject {
    private var recorder: AVAudioRecorder?
    private let recognizer = SFSpeechRecognizer(locale: Locale(identifier: "de-DE"))!

    func startRecording() throws {
        let url = URL.documentsDirectory.appending(path: "voice.m4a")
        let settings: [String:Any] = [
            AVFormatIDKey: kAudioFormatMPEG4AAC,
            AVSampleRateKey: 44100,
            AVNumberOfChannelsKey: 1
        ]
        recorder = try AVAudioRecorder(url: url, settings: settings)
        recorder?.record()
    }

    func stopAndTranscribe() {
        recorder?.stop()
        guard let url = recorder?.url else { return }

        let request = SFSpeechURLRecognitionRequest(url: url)
        recognizer.recognitionTask(with: request) { result, _ in
            if let text = result?.bestTranscription.formattedString {
                print("📄 Transkript: \(text)")
            }
        }
    }
}

func detectKeywords(_ text: String) {
    let t = text.lowercased()

    if t.contains("hey slayken") {
        print("🟡 Wake Word erkannt: Hey Slayken!")
    }
    if t.contains("attack") || t.contains("angriff") {
        print("⚔️ Attack Voice Command")
    }
    if t.contains("heal") || t.contains("heilen") {
        print("💚 Heal Voice Command")
    }
}

func splitIntoSentences(_ text: String) -> [String] {
    let delimiters = [".", "?", "!"]
    var sentences: [String] = []
    var buffer = ""

    for char in text {
        buffer.append(char)
        if delimiters.contains(String(char)) {
            sentences.append(buffer.trimmingCharacters(in: .whitespaces))
            buffer = ""
        }
    }
    return sentences
}

import AVFoundation

func analyzeTone(_ buffer: AVAudioPCMBuffer) {
    let rms = sqrt(buffer.floatChannelData![0].reduce(0) { $0 + $1*$1 } / Float(buffer.frameLength))

    if rms > 0.25 {
        print("😡 Laut / Stressig")
    } else if rms < 0.05 {
        print("😴 Sehr leise / ruhig")
    } else {
        print("🙂 Normal gesprochen")
    }
}

